    const visited: Map<number, Map<number, Map<number, number>>> = new Map();
    for (let i = 0; i < m; i++) {
        visited.set(i, new Map());
        for (let j = 0; j < n; j++) {
            visited.get(i)!.set(j, new Map());
        }
    }

    while (heap.length > 0) {
        heap.sort((a, b) => a[0] - b[0]); // Priority queue simulation
        const [cost, i, j, remainingK] = heap.shift()!;

        if (i === m - 1 && j === n - 1) {
            return cost;
